/* DeliveryAddress.selectList */
SELECT 
FROM TB_DELIVERY_ADDRESS
WHERE SOCIAL_ACCOUNT_ID = #{socialAccountId}
  AND DEL_YN = 'N'
ORDER BY IS_DEFAULT DESC, ID DESC

/* DeliveryAddress.selectById */
SELECT 
FROM TB_DELIVERY_ADDRESS
WHERE ID = #{id}
  AND DEL_YN = 'N'

mapper.update:
/* DeliveryAddress.delete */
UPDATE TB_DELIVERY_ADDRESS
SET DEL_YN = 'Y',
    UPT_TM = NOW()
WHERE ID = #{id}
